    public Object parseWsTicker(Object ticker, Object... optionalArgs)
    {
        //
        //  public
        //    {
        //        "symbol1": "LRC",
        //        "symbol2": "USD",
        //        "price": "0.305",
        //        "open24": "0.301",
        //        "volume": "241421.641700"
        //    }
        //  private
        //    {
        //        "timestamp": "1663764969",
        //        "low": "18756.3",
        //        "high": "19200",
        //        "last": "19200",
        //        "volume": "0.94735907",
        //        "volume30d": "64.61299999",
        //        "bid": 19217.2,
        //        "ask": 19247.5,
        //        "priceChange": "44.3",
        //        "priceChangePercentage": "0.23",
        //        "pair": ["BTC", "USDT"]
        //    }
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object pair = this.safeValue(ticker, "pair", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object baseId = this.safeString(ticker, "symbol1");
        if (Helpers.isTrue(Helpers.isEqual(baseId, null)))
        {
            baseId = this.safeString(pair, 0);
        }
        Object quoteId = this.safeString(ticker, "symbol2");
        if (Helpers.isTrue(Helpers.isEqual(quoteId, null)))
        {
            quoteId = this.safeString(pair, 1);
        }
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object symbol = Helpers.add(Helpers.add(base, "/"), quote);
        Object timestamp = this.safeInteger(ticker, "timestamp");
        if (Helpers.isTrue(!Helpers.isEqual(timestamp, null)))
        {
            timestamp = Helpers.multiply(timestamp, 1000);
        }
        final Object finalTimestamp = timestamp;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", finalTimestamp );
            put( "datetime", CexCore.this.iso8601(finalTimestamp) );
            put( "high", CexCore.this.safeString(ticker, "high") );
            put( "low", CexCore.this.safeString(ticker, "low") );
            put( "bid", CexCore.this.safeString(ticker, "bid") );
            put( "bidVolume", null );
            put( "ask", CexCore.this.safeString(ticker, "ask") );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", CexCore.this.safeString(ticker, "open24") );
            put( "close", null );
            put( "last", CexCore.this.safeString2(ticker, "price", "last") );
            put( "previousClose", null );
            put( "change", CexCore.this.safeString(ticker, "priceChange") );
            put( "percentage", CexCore.this.safeString(ticker, "priceChangePercentage") );
            put( "average", null );
            put( "baseVolume", null );
            put( "quoteVolume", CexCore.this.safeString(ticker, "volume") );
            put( "info", ticker );
        }}, market);
    }

