    public Object handleErrorMessage(Client client, Object message)
    {
        try
        {
            Object data = this.safeValue(message, "data", new java.util.HashMap<String, Object>() {{}});
            Object error = this.safeString(data, "error");
            Object eventVar = this.safeString(message, "e", "");
            Object feedback = Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " "), eventVar), " "), error);
            this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), error, feedback);
            this.throwBroadlyMatchedException(Helpers.GetValue(this.exceptions, "broad"), error, feedback);
            throw new ExchangeError((String)feedback) ;
        } catch(Exception error)
        {
            Object messageHash = this.safeString(message, "oid");
            Object future = this.safeValue(Helpers.GetValue(client, "futures"), ((String)messageHash));
            if (Helpers.isTrue(!Helpers.isEqual(future, null)))
            {
                client.reject(error, messageHash);
                return true;
            } else
            {
                throw error;
            }
        }
    }

    public void handleMessage(Client client, Object message)
    {
        Object ok = this.safeString(message, "ok");
        if (Helpers.isTrue(Helpers.isEqual(ok, "error")))
        {
            this.handleErrorMessage(client, message);
            return;
        }
        Object eventVar = this.safeString(message, "e");
        Object handlers = new java.util.HashMap<String, Object>() {{
            put( "auth", "handleAuthenticationMessage");
            put( "connected", "handleConnected");
            put( "tick", "handleTicker");
            put( "ticker", "handleTicker");
            put( "init-ohlcv-data", "handleInitOHLCV");
            put( "ohlcv24", "handleOHLCV24");
            put( "ohlcv1m", "handleOHLCV1m");
            put( "ohlcv", "handleOHLCV");
            put( "get-balance", "handleBalance");
            put( "order-book-subscribe", "handleOrderBookSnapshot");
            put( "md_update", "handleOrderBookUpdate");
            put( "open-orders", "resolveData");
            put( "order", "handleOrderUpdate");
            put( "history-update", "handleTrade");
            put( "history", "handleTradesSnapshot");
            put( "tx", "handleTransaction");
            put( "place-order", "resolveData");
            put( "cancel-replace-order", "resolveData");
            put( "cancel-order", "resolveData");
            put( "mass-cancel-place-orders", "resolveData");
            put( "get-order", "resolveData");
        }};
        Object handler = this.safeValue(handlers, ((String)eventVar));
        if (Helpers.isTrue(!Helpers.isEqual(handler, null)))
        {
            Helpers.callDynamically(this, handler, new Object[] {client, message});
        }
    }

